patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 756b25ac9856..ef66a51aee87 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -21002,9 +21002,7 @@ bool SLPVectorizerPass::vectorizeGEPIndices(BasicBlock *BB, BoUpSLP &R) {
       //
       // where the loads of "a", the loads of "b", and the subtractions can be
       // performed in parallel. It's likely that detecting this pattern in a
-      // bottom-up phase will be simpler and less costly than building a
-      // full-blown top-down phase beginning at the consecutive loads.
-      Changed |= tryToVectorizeList(Bundle, R);
+      Changed |= (all_of(Bundle, [&](Value *V) { auto *I = dyn_cast<Instruction>(V); return !I || I->getParent() == BB; }) && tryToVectorizeList(Bundle, R));
     }
   }
   return Changed;

test_traj:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 756b25ac9856..95402c17ef64 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -21004,6 +21004,20 @@ bool SLPVectorizerPass::vectorizeGEPIndices(BasicBlock *BB, BoUpSLP &R) {
       // performed in parallel. It's likely that detecting this pattern in a
       // bottom-up phase will be simpler and less costly than building a
       // full-blown top-down phase beginning at the consecutive loads.
+      // Do not vectorize if the indices are not in the same basic block.
+      {
+        bool AllInBB = true;
+        for (Value *V : VectorizableIndices) {
+          if (auto *I = dyn_cast<Instruction>(V)) {
+            if (I->getParent() != BB) {
+              AllInBB = false;
+              break;
+            }
+          }
+        }
+        if (!AllInBB)
+          continue;
+      }
       Changed |= tryToVectorizeList(Bundle, R);
     }
   }
